INSERT INTO [QuizSystem].[dbo].[Questions] (CreationTime, QuestionText, ImagePath, QuestionType, DefaultMark, ParentQuestionId, FeedbackMessage, QuestionName, QuestionCategoryId, QuestionStatus, CreatorUserId, LastModificationTime, LastModifierUserId, AdminReviewText, UserReportText, SortOrder, VocabLevel, ReviewFeedbackStatus, HighLight, DragDrop, WordOrderSeeds, DragDropImageHeight, DragDropImageUrl, DragDropImageWidth, DragDropRedundantAnswer, Grade, EnableStepByStepGuide, DisplayNote, Note, ShowRelatedTopicDetail, StepByStepGuide, EssayAnswerLines, EnableShortAnswer, ShowOnQuizOnly, Difficulty, CognitiveLevel, DisplayNotePosition, QuestionTextSupplement, DisplayAllChildren, AIReviewText, QuestionState, Hint) VALUES (GETDATE(), '{{outnumber}}', NULL, 1, 0, 973722, NULL, NULL, NULL, 0, 23030, NULL, NULL, NULL, NULL, 1, NULL, 0, NULL, 0, NULL, 0, NULL, 0, NULL, NULL, 0, 0, NULL, 0, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 0, NULL, 0, '<p>Chỗ trống cần một <strong>động từ</strong> để diễn tả số lượng của phụ nữ so với đ&agrave;n &ocirc;ng. Nếu l&agrave; "four to one", c&oacute; nghĩa l&agrave; phụ nữ chiếm số đ&ocirc;ng, đ&ocirc;ng hơn đ&agrave;n &ocirc;ng. Từ "number" c&oacute; thể biến th&agrave;nh động từ mang &yacute; nghĩa n&agrave;y.</p>');
INSERT INTO [QuizSystem].[dbo].[Questions] (CreationTime, QuestionText, ImagePath, QuestionType, DefaultMark, ParentQuestionId, FeedbackMessage, QuestionName, QuestionCategoryId, QuestionStatus, CreatorUserId, LastModificationTime, LastModifierUserId, AdminReviewText, UserReportText, SortOrder, VocabLevel, ReviewFeedbackStatus, HighLight, DragDrop, WordOrderSeeds, DragDropImageHeight, DragDropImageUrl, DragDropImageWidth, DragDropRedundantAnswer, Grade, EnableStepByStepGuide, DisplayNote, Note, ShowRelatedTopicDetail, StepByStepGuide, EssayAnswerLines, EnableShortAnswer, ShowOnQuizOnly, Difficulty, CognitiveLevel, DisplayNotePosition, QuestionTextSupplement, DisplayAllChildren, AIReviewText, QuestionState, Hint) VALUES (GETDATE(), '{{made it impossible for the [students|pupils]}}', NULL, 1, 0, 973790, NULL, NULL, NULL, 0, 23030, NULL, NULL, NULL, NULL, 1, NULL, 0, NULL, 0, NULL, 0, NULL, 0, NULL, NULL, 0, 0, NULL, 0, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 0, NULL, 0, '<p>C&acirc;u gốc diễn tả một mối quan hệ nguy&ecirc;n nh&acirc;n - kết quả: "những chỉ dẫn phức tạp" (nguy&ecirc;n nh&acirc;n) đ&atilde; l&agrave;m cho "học sinh bị bối rối" (kết quả).</p>
INSERT INTO [QuizSystem].[dbo].[Questions] (CreationTime, QuestionText, ImagePath, QuestionType, DefaultMark, ParentQuestionId, FeedbackMessage, QuestionName, QuestionCategoryId, QuestionStatus, CreatorUserId, LastModificationTime, LastModifierUserId, AdminReviewText, UserReportText, SortOrder, VocabLevel, ReviewFeedbackStatus, HighLight, DragDrop, WordOrderSeeds, DragDropImageHeight, DragDropImageUrl, DragDropImageWidth, DragDropRedundantAnswer, Grade, EnableStepByStepGuide, DisplayNote, Note, ShowRelatedTopicDetail, StepByStepGuide, EssayAnswerLines, EnableShortAnswer, ShowOnQuizOnly, Difficulty, CognitiveLevel, DisplayNotePosition, QuestionTextSupplement, DisplayAllChildren, AIReviewText, QuestionState, Hint) VALUES (GETDATE(), '{{defame}}', NULL, 1, 0, 978357, NULL, NULL, NULL, 0, 23030, NULL, NULL, NULL, NULL, 1, NULL, 0, NULL, 0, NULL, 0, NULL, 0, NULL, NULL, 0, 0, NULL, 0, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 0, NULL, 0, '<p>Chỗ trống đứng sau "to" (trong "in an attempt to"), vậy cần một <strong>động từ nguy&ecirc;n thể</strong>. Người quản l&yacute; tồi th&igrave; mọi người sẽ muốn l&agrave;m mất danh tiếng của anh ta. H&atilde;y nghĩ từ "fame" (danh tiếng) c&oacute; thể biến đổi th&agrave;nh động từ mang nghĩa ngược lại, hoặc l&agrave;m hỏng danh tiếng.</p>');
